insert into recipes (id, name, description, servings) values
  ('b0000000-0000-0000-0000-000000000001', 'Shepherd''s Pie',       'Classic comfort food with lamb mince and creamy mashed potato topping.',                4),
  ('b0000000-0000-0000-0000-000000000002', 'Lasagna',               'Layered beef ragu with bechamel sauce and melted cheese.',                              6),
  ('b0000000-0000-0000-0000-000000000003', 'Spaghetti Bolognese',   'A weeknight staple. Rich beef ragu served over spaghetti.',                             4),
  ('b0000000-0000-0000-0000-000000000004', 'Chicken Stir Fry',      'Quick and healthy stir fry with chicken and veg, served with rice.',                    2),
  ('b0000000-0000-0000-0000-000000000005', 'Bangers and Mash',      'Pork sausages with creamy mash and onion gravy.',                                      4),
  ('b0000000-0000-0000-0000-000000000006', 'Chilli Con Carne',      'Spiced beef chilli with kidney beans, served with rice.',                               4),
  ('b0000000-0000-0000-0000-000000000007', 'Chicken Tikka Masala',  'Chicken in a creamy spiced tomato sauce, served with rice and naan.',                   4),
  ('b0000000-0000-0000-0000-000000000008', 'Toad in the Hole',      'Pork sausages baked in crispy Yorkshire pudding batter.',                               4),
  ('b0000000-0000-0000-0000-000000000009', 'Roast Chicken Dinner',  'Classic Sunday roast with roast potatoes, carrots, and gravy.',                         4),
  ('b0000000-0000-0000-0000-000000000010', 'Fish Pie',              'Creamy pie with cod, smoked haddock, and prawns under mashed potato.',                  4),
  ('b0000000-0000-0000-0000-000000000011', 'Chicken Fajitas',       'Spiced chicken with peppers and onions in warm tortilla wraps.',                        4),
  ('b0000000-0000-0000-0000-000000000012', 'Macaroni Cheese',       'Creamy baked macaroni cheese with a crispy top.',                                       4),
  ('b0000000-0000-0000-0000-000000000013', 'Beef Stew',             'Hearty slow-cooked beef stew with root vegetables.',                                   4),
  ('b0000000-0000-0000-0000-000000000014', 'Sausage Casserole',     'One-pot sausage casserole with butter beans in a tomato sauce.',                        4),
  ('b0000000-0000-0000-0000-000000000015', 'Carbonara',             'Quick creamy pasta with pancetta, egg, and parmesan.',                                  2),
  ('b0000000-0000-0000-0000-000000000016', 'Jacket Potato with Beans and Cheese', 'Simple baked potato topped with baked beans and melted cheddar.',          2),
  ('b0000000-0000-0000-0000-000000000017', 'Vegetable Curry',         'Chickpea and spinach curry in a creamy coconut sauce, served with rice.',               4),
  ('b0000000-0000-0000-0000-000000000018', 'Mushroom Risotto',        'Creamy Italian risotto with mushrooms and parmesan.',                                   4),
  ('b0000000-0000-0000-0000-000000000019', 'Veggie Chilli',           'Hearty three-bean chilli with peppers and sweetcorn, served with rice.',                4),
  ('b0000000-0000-0000-0000-000000000020', 'Cauliflower Cheese',      'Tender cauliflower baked in a rich cheese sauce.',                                      4),
  ('b0000000-0000-0000-0000-000000000021', 'Mushroom Stroganoff',     'Creamy mushroom stroganoff with paprika and sour cream, served with rice.',             4),
  ('b0000000-0000-0000-0000-000000000022', 'Spinach and Ricotta Cannelloni', 'Pasta tubes stuffed with spinach and ricotta in a tomato sauce.',                4),
  ('b0000000-0000-0000-0000-000000000023', 'Vegetable Stir Fry',      'Quick veggie stir fry with broccoli, peppers, and mushrooms in soy sauce.',             2),
  ('b0000000-0000-0000-0000-000000000024', 'Red Lentil Dhal',         'Spiced red lentil dhal with coconut milk, served with rice and naan.',                  4),
  ('b0000000-0000-0000-0000-000000000025', 'Halloumi and Veg Traybake', 'Roasted halloumi with courgette, peppers, and cherry tomatoes.',                      4),
  ('b0000000-0000-0000-0000-000000000026', 'Cheese and Onion Pie',    'Flaky puff pastry pie filled with cheese and caramelised onion.',                       4),
  ('b0000000-0000-0000-0000-000000000027', 'Pasta Primavera',         'Penne with roasted courgette, cherry tomatoes, and fresh basil.',                       4),
  ('b0000000-0000-0000-0000-000000000028', 'Veggie Fajitas',          'Spiced peppers, onions, and mushrooms in warm tortilla wraps.',                         4),
  ('b0000000-0000-0000-0000-000000000029', 'Sweet Potato and Chickpea Curry', 'Warming sweet potato curry with chickpeas and spinach.',                        4),
  ('b0000000-0000-0000-0000-000000000030', 'Vegetable Lasagna',       'Layered lasagna with roasted veg, tomato sauce, and bechamel.',                         6),
  ('b0000000-0000-0000-0000-000000000031', 'Aubergine Parmigiana',    'Baked layers of aubergine with tomato sauce and melted mozzarella.',                    4),
  ('b0000000-0000-0000-0000-000000000032', 'Bean and Vegetable Soup', 'Hearty chunky soup with cannellini beans and root vegetables.',                         4);
